import React, { useMemo, useState } from "react";

export default function Sidebar({
  user,
  rooms,
  activeRoom,
  onSelectRoom,
  onCreateRoomOpen,
  onJoinRoom,
  onLeaveRoom,
  onDeleteRoom,
  onLogout,
  theme,
  onThemeChange,
  connected
}) {
  const [query, setQuery] = useState("");
  const themes = [
    { id: "ocean", label: "Ocean Blue" },
    { id: "sunset", label: "Sunset Orange" },
    { id: "forest", label: "Forest Green" },
    { id: "midnight", label: "Midnight" },
    { id: "lavender", label: "Lavender" }
  ];

  const filteredRooms = useMemo(
    () => rooms.filter((room) => `${room.name} ${room.description || ""}`.toLowerCase().includes(query.toLowerCase())),
    [rooms, query]
  );

  return (
    <aside className="sidebar">
      <div className="icon-rail">
        <button type="button" className="rail-btn active">CH</button>
        <button type="button" className="rail-btn">MS</button>
        <button type="button" className="rail-btn">GR</button>
        <button type="button" className="rail-btn">VD</button>
        <button type="button" className="rail-btn">NT</button>
        <div className="rail-spacer" />
        <button type="button" className="rail-btn">TH</button>
        <button type="button" className="rail-btn" onClick={onLogout}>OUT</button>
      </div>

      <div className="sidebar-main glass">
        <div className="sidebar-head">
          <h2>Chat</h2>
          <button className="add-room-btn" onClick={onCreateRoomOpen} type="button">+</button>
        </div>

        <label className="search-wrap">
          <span>Q</span>
          <input
            type="text"
            value={query}
            onChange={(event) => setQuery(event.target.value)}
            placeholder="Search contact"
            aria-label="Search rooms"
          />
        </label>

        <div className="status-row">
          <span className={connected ? "status connected" : "status disconnected"}>{connected ? "Online" : "Connecting..."}</span>
          <small>{user?.username}</small>
        </div>

        <div className="room-list">
          {filteredRooms.map((room) => {
            const isMember = room.members?.some((member) => (member._id || member.id) === user?.id);
            const isAdmin = room.admins?.some((admin) => (admin._id || admin.id) === user?.id) || (room.createdBy?._id || room.createdBy?.id) === user?.id;
            const isActive = activeRoom?._id === room._id;

            return (
              <article key={room._id} className={isActive ? "room-card active" : "room-card"}>
                <button type="button" onClick={() => onSelectRoom(room)} className="room-main-btn">
                  <strong>{room.name}</strong>
                  <span>{room.description || "chat"}</span>
                  <small>{room.members?.length || 0}</small>
                </button>
                <div className="room-actions">
                  {!isMember ? <button className="ghost-btn" type="button" onClick={() => onJoinRoom(room._id)}>Join</button> : null}
                  {isMember ? <button className="ghost-btn" type="button" onClick={() => onLeaveRoom(room._id)}>Leave</button> : null}
                  {isAdmin ? <button className="danger-btn" type="button" onClick={() => onDeleteRoom(room._id)}>Delete</button> : null}
                </div>
              </article>
            );
          })}
        </div>

        <div className="theme-picker compact">
          <label htmlFor="theme-select">Theme</label>
          <select id="theme-select" value={theme} onChange={(event) => onThemeChange(event.target.value)}>
            {themes.map((item) => <option value={item.id} key={item.id}>{item.label}</option>)}
          </select>
        </div>
      </div>
    </aside>
  );
}
